parameters.jsCode:
const seenKeys = new Set();
const results = [];
for (const item of $input.all()) {
  const rawUrl = item.json.website || "";
  const title = item.json.title || "no-title";
  let key = "";
  // 1. Generate the key
  if (rawUrl && rawUrl.trim() !== "" && rawUrl !== "null") {
    key = rawUrl
      .replace(/^(?:https?:\/\/)?(?:www\.)?/i, "")
      .split('/')[0]
      .toLowerCase();
  } else {
    key = "no-web-" + title.toLowerCase().replace(/[^a-z0-9]/g, "");
  }
  // 2. ONLY add to results if we haven't seen this key in THIS run yet
  if (!seenKeys.has(key)) {
    seenKeys.add(key);
    item.json.domainKey = key;
    results.push(item);
  }
}
return results;

const rows = [["domain"]];

const firstItem = $input.all()[0].json;
const state = (firstItem.output?.state || firstItem.fields?.state || "Bulk_Enrichment").replace(/\s+/g, '_');


const now = new Date();
const dateStr = now.toISOString().split('T')[0]; 

const hours = String(now.getHours()).padStart(2, '0');
const minutes = String(now.getMinutes()).padStart(2, '0');
const timeStr = `${hours}-${minutes}`;

for (const item of $input.all()) {
  const domain = item.json.output?.domainKey || item.json.fields?.domainKey;

  if (domain && domain.trim() !== "") {
    rows.push([domain]); 
  }
}

return {
  data: rows,
  domain_field_index: 0,

  file_name: `${state}_${dateStr}_${timeStr}`
};

const csvString = $input.first().json.data;
const lines = csvString.split('\n');
const headers = lines[0].split(',');
const results = [];

for (let i = 1; i < lines.length; i++) {
  const currentLine = lines[i].split(',');

  if (currentLine.length === headers.length) {
    let obj = {};
    for (let j = 0; j < headers.length; j++) {
      obj[headers[j].trim()] = currentLine[j].trim();
    }
    results.push(obj);
  }
}

return results;

for (const item of $input.all()) {
  const type = item.json.emails_type;

  if (type === 'valid') {
    item.json.status = '✅ Verified';
  } else if (type === 'risky') {
    item.json.status = '⚠️ Risky - Manual Check';
  } else {
    item.json.status = '❌ Not Found';
  }
}

return $input.all();

